1	"use client";
2	
3	import {
4	  useCallback,
5	  useEffect,
6	  useMemo,
7	  useRef,
8	  useState,
9	  type ChangeEvent,
10	  type KeyboardEvent,
11	} from "react";
12	import {
13	  listFollowupMessages,
14	  streamFollowup,
15	} from "@/lib/currentsApi";
16	import type {
17	  PublicCitation,
18	  PublicFollowupMessage,
19	} from "@/lib/currentsTypes";
20	import { renderSafeMarkdown } from "@/lib/safeMarkdown";
21	import {
22	  loadSessionId,
23	  saveSessionId,
24	} from "@/lib/followupSession";
25	
26	// Client-side rate limit between sends, in ms. The server enforces its own
27	// (much stricter) limit — this just keeps eager double-clicks from firing.
28	const SEND_COOLDOWN_MS = 2000;
29	
30	// Minimum cosmetic textarea height (1 line) and maximum (~6 lines).
31	const TEXTAREA_MIN = 38;
32	const TEXTAREA_MAX = 160;
33	
34	type LocalMessage = {
35	  id: string;
36	  role: "user" | "assistant" | "system";
37	  content: string;
38	  citations: PublicCitation[];
39	  refused: boolean;
40	  refusal_reason: string | null;
41	  // Optional presentational flag so error frames render with a tint.
42	  isError?: boolean;
43	};
44	
45	type Pending = {
46	  text: string;
47	  citations: PublicCitation[];
48	} | null;
49	
50	export function FollowupChat({ opinionId }: { opinionId: string }) {
51	  const [messages, setMessages] = useState<LocalMessage[]>([]);
52	  const [pending, setPending] = useState<Pending>(null);
53	  const [input, setInput] = useState("");
54	  const [busy, setBusy] = useState(false);
55	  const [inlineError, setInlineError] = useState<string | null>(null);
56	
57	  const sessionIdRef = useRef<string | null>(null);
58	  const lastSentAtRef = useRef<number>(0);
59	  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
60	  const listEndRef = useRef<HTMLDivElement | null>(null);
61	
62	  // Load session + history on mount. Never auto-ask.
63	  useEffect(() => {
64	    const sid = loadSessionId(opinionId);
65	    if (!sid) return;
66	    sessionIdRef.current = sid;
67	    let cancelled = false;
68	    (async () => {
69	      try {
70	        const history = await listFollowupMessages(opinionId, sid);
71	        if (cancelled) return;
72	        setMessages(
73	          history.map((m: PublicFollowupMessage) => ({
74	            id: m.id,
75	            role: m.role,
76	            content: m.content,
77	            citations: m.citations,
78	            refused: m.refused,
79	            refusal_reason: m.refusal_reason,
80	          })),
81	        );
82	      } catch {
83	        // If history fails (e.g. TTL expired), silently drop the session;
84	        // the user can still start a new conversation.
85	      }
86	    })();
87	    return () => {
88	      cancelled = true;
89	    };
90	  }, [opinionId]);
91	
92	  // Auto-scroll to bottom when messages or pending text change.
93	  useEffect(() => {
94	    listEndRef.current?.scrollIntoView({ block: "end" });
95	  }, [messages, pending?.text, pending?.citations.length]);
96	
97	  // Auto-grow textarea height.
98	  const resizeTextarea = useCallback(() => {
99	    const el = textareaRef.current;
100	    if (!el) return;
101	    el.style.height = "auto";
102	    const next = Math.min(Math.max(el.scrollHeight, TEXTAREA_MIN), TEXTAREA_MAX);
103	    el.style.height = `${next}px`;
104	  }, []);
105	
106	  useEffect(() => {
107	    resizeTextarea();
108	  }, [input, resizeTextarea]);
109	
110	  const onInputChange = (e: ChangeEvent<HTMLTextAreaElement>) => {
111	    setInput(e.target.value);
112	  };
113	
114	  const send = useCallback(async () => {
115	    const question = input.trim();
116	    if (!question) return;
117	    if (busy) return;
118	
119	    const now = Date.now();
120	    if (now - lastSentAtRef.current < SEND_COOLDOWN_MS) {
121	      setInlineError(
122	        "Slow down — wait a couple of seconds between messages.",
123	      );
124	      return;
125	    }
126	    lastSentAtRef.current = now;
127	    setInlineError(null);
128	
129	    const userLocal: LocalMessage = {
130	      id: `local-user-${now}`,
131	      role: "user",
132	      content: question,
133	      citations: [],
134	      refused: false,
135	      refusal_reason: null,
136	    };
137	    setMessages((prev) => [...prev, userLocal]);
138	    setInput("");
139	    setBusy(true);
140	    setPending({ text: "", citations: [] });
141	
142	    try {
143	      const body: { question: string; session_id?: string } = { question };
144	      if (sessionIdRef.current) body.session_id = sessionIdRef.current;
145	
146	      let accText = "";
147	      const accCitations: PublicCitation[] = [];
148	      let finalRefused = false;
149	      let finalReason: string | null = null;
150	      let sawError: string | null = null;
151	
152	      for await (const frame of streamFollowup(opinionId, body)) {
153	        if (frame.kind === "meta") {
154	          sessionIdRef.current = frame.data.session_id;
155	          saveSessionId(opinionId, frame.data.session_id);
156	        } else if (frame.kind === "token") {
157	          accText += frame.data;
158	          setPending({ text: accText, citations: [...accCitations] });
159	        } else if (frame.kind === "citation") {
160	          accCitations.push(frame.data);
161	          setPending({ text: accText, citations: [...accCitations] });
162	        } else if (frame.kind === "done") {
163	          finalRefused = frame.data.refused;
164	          finalReason = frame.data.refusal_reason;
165	        } else if (frame.kind === "error") {
166	          sawError =
167	            frame.data.reason ||
168	            frame.data.error ||
169	            "The firm could not answer that follow-up.";
170	        }
171	      }
172	
173	      if (sawError) {
174	        setMessages((prev) => [
175	          ...prev,
176	          {
177	            id: `local-err-${Date.now()}`,
178	            role: "assistant",
179	            content: sawError ?? "Error.",
180	            citations: [],
181	            refused: false,
182	            refusal_reason: null,
183	            isError: true,
184	          },
185	        ]);
186	      } else {
187	        setMessages((prev) => [
188	          ...prev,
189	          {
190	            id: `local-asst-${Date.now()}`,
191	            role: "assistant",
192	            content: accText,
193	            citations: accCitations,
194	            refused: finalRefused,
195	            refusal_reason: finalReason,
196	          },
197	        ]);
198	      }
199	    } catch (e) {
200	      const status = (e as { status?: number } | null)?.status;
201	      const copy =
202	        status === 429
203	          ? "You've hit the follow-up rate limit. Try again in a few minutes."
204	          : "Couldn't reach the firm. Try again in a moment.";
205	      setMessages((prev) => [
206	        ...prev,
207	        {
208	          id: `local-err-${Date.now()}`,
209	          role: "assistant",
210	          content: copy,
211	          citations: [],
212	          refused: false,
213	          refusal_reason: null,
214	          isError: true,
215	        },
216	      ]);
217	    } finally {
218	      setPending(null);
219	      setBusy(false);
220	    }
221	  }, [input, busy, opinionId]);
222	
223	  const onKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
224	    if (e.key === "Enter" && !e.shiftKey) {
225	      e.preventDefault();
226	      void send();
227	    }
228	    // Shift+Enter: allow the native newline insertion.
229	  };
